<script setup lang="ts">import{ref}from'vue';import{useRouter}from'vue-router';import{addDaysToDateInput,toLocalDateInputValue}from'@/lib/local-date';import{fetchReservationSlots,createReservation}from'@/services/reservation';import type{ReservationSlot}from'@/types/reservation';const props=defineProps<{shopId:number}>(),router=useRouter(),minimumDate=toLocalDateInputValue(),date=ref(addDaysToDateInput(minimumDate,1)),people=ref(2),slots=ref<ReservationSlot[]>([]),selected=ref<ReservationSlot|null>(null),contactName=ref(''),contactPhone=ref(''),remark=ref(''),errorMessage=ref('');async function search(){try{slots.value=(await fetchReservationSlots(props.shopId,date.value,people.value)).list;selected.value=null}catch(e){errorMessage.value=e instanceof Error?e.message:'时段加载失败'}}async function submit(){if(!selected.value){errorMessage.value='先选一个可订时段。';return}try{const r=await createReservation({shopId:props.shopId,slotId:selected.value.slotId,reserveTime:`${date.value} ${selected.value.startTime}`,peopleCount:people.value,contactName:contactName.value,contactPhone:contactPhone.value,remark:remark.value});await router.push(`/user/reservations/${r.id}`)}catch(e){errorMessage.value=e instanceof Error?e.message:'预订提交失败'}}</script>
<template><section class="page-section"><div class="page-header"><div><p class="eyebrow">在线预订</p><h1>先看真实余量，再提交联系人信息。</h1></div></div><p v-if="errorMessage" class="feedback is-error">{{errorMessage}}</p><section class="content-card"><div class="form-grid form-grid--two"><label class="field"><span>日期</span><input v-model="date" type="date" :min="minimumDate"></label><label class="field"><span>人数</span><input v-model.number="people" type="number" min="1" max="50"></label></div><button class="primary-button" @click="search">查询时段</button><div class="tag-row"><button v-for="slot in slots" :key="slot.slotId" type="button" class="secondary-button" :disabled="!slot.available" @click="selected=slot">{{slot.startTime}}-{{slot.endTime}} · 余 {{slot.remainingCount}} · {{slot.confirmModeText}}</button></div><div class="form-grid form-grid--two"><label class="field"><span>联系人</span><input v-model="contactName"></label><label class="field"><span>联系电话</span><input v-model="contactPhone" placeholder="+8613812345678"></label><label class="field field--full"><span>备注</span><input v-model="remark" placeholder="靠窗 / 包厢"></label></div><button class="primary-button" @click="submit">提交预订</button></section></section></template>
